clients = {}
authorization_codes = {}
access_tokens = {}

def register_client(client_id, redirect_uri, client_secret=None):
    if client_secret is None:
        client_secret = secrets.token_urlsafe(32)
    
    clients[client_id] = {
        'redirect_uri': redirect_uri,
        'client_secret': client_secret
    }
    return client_secret

def validate_redirect_uri(client_id, redirect_uri):
    if client_id not in clients:
        return False
    
    registered_uri = clients[client_id]['redirect_uri']
    return redirect_uri.startswith(registered_uri)

def generate_authorization_code(client_id, redirect_uri, scope=None):
    code = secrets.token_urlsafe(32)
    authorization_codes[code] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': scope,
        'expires_at': datetime.now() + timedelta(minutes=10),
        'used': False
    }
    return code

def generate_access_token(client_id, scope=None):
    token = secrets.token_urlsafe(32)
    access_tokens[token] = {
        'client_id': client_id,
        'scope': scope,
        'expires_at': datetime.now() + timedelta(hours=1)
    }
    return token

def validate_authorization_code(code, client_id, redirect_uri):
    if code not in authorization_codes:
        return False
    
    auth_code = authorization_codes[code]
    
    if auth_code['used']:
        return False
    
    if auth_code['expires_at'] < datetime.now():
        return False
    
    if auth_code['client_id'] != client_id:
        return False
    
    if auth_code['redirect_uri'] != redirect_uri:
        return False
    
    return True

def validate_client_credentials(client_id, client_secret):
    if client_id not in clients:
        return False
    return clients[client_id]['client_secret'] == client_secret

class OAuthHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        parsed_path = urlparse(self.path)
        
