        code = generate_authorization_code(client_id, redirect_uri, scope)
        
        redirect_url = f"{redirect_uri}?code={code}"
        if state:
            redirect_url += f"&state={state}"
        
        self.send_response(302)
        self.send_header('Location', redirect_url)
        self.end_headers()
    
